import{_ as e,o as l,c as r,af as o}from"./chunks/framework.BSym9njW.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/01-deploy/index.md","filePath":"zh/01-deploy/index.md","lastUpdated":1782210600000}'),n={name:"zh/01-deploy/index.md"};function t(m,a,s,i,p,h){return l(),r("div",null,[...a[0]||(a[0]=[o(`<div align="center"><h1>01-Deploy</h1><strong>🚀 ROCm 大模型部署实践</strong></div><div align="center"><p><em>零基础快速上手 AMD GPU 大模型部署</em></p><p><a href="/hello-rocm/zh/">返回主页</a> · <a href="/hello-rocm/01-deploy/">English</a></p></div><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>  本模块提供在 AMD GPU 上部署大语言模型的完整教程。无论你是初学者还是有经验的开发者，都可以通过本教程快速掌握在 ROCm 平台上部署和运行大模型的方法。</p><p>  自 ROCm 7.10.0 起，ROCm 已支持像 CUDA 一样在 Python 虚拟环境中无缝安装，这大大降低了 AMD GPU 大模型部署的门槛。</p><p>  本模块默认以 <strong>Google Gemma 4</strong>（<code>gemma-4-E4B-it</code> 为主）作为示例模型，同时提供 <strong>Qwen3</strong> 的平行教程供参考。目录结构如下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>01-Deploy/</span></span>
<span class="line"><span>└── models/</span></span>
<span class="line"><span>    ├── Gemma4/           # 以 Gemma 4 为主的部署教程（主推荐）</span></span>
<span class="line"><span>    ├── Qwen3/            # Qwen3 系列部署教程（参考对比）</span></span>
<span class="line"><span>    └── Qwen3.5/          # Qwen3.5 系列部署教程（新架构参考）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="教程列表" tabindex="-1">教程列表 <a class="header-anchor" href="#教程列表" aria-label="Permalink to &quot;教程列表&quot;">​</a></h2><h3 id="ubuntu-24-04-rocm-7-环境准备教程" tabindex="-1">Ubuntu 24.04 + ROCm 7 环境准备教程 <a class="header-anchor" href="#ubuntu-24-04-rocm-7-环境准备教程" aria-label="Permalink to &quot;Ubuntu 24.04 + ROCm 7 环境准备教程&quot;">​</a></h3><p>  本教程将手把手带你在 Ubuntu 24.04 上完成 ROCm 7.1.0 的安装与验证，包括卸载旧 ROCm 环境、运行官方脚本安装 ROCm、以及使用 <code>rocminfo</code> / <code>rocm-smi</code> / <code>amd-smi</code> 等工具确认 GPU 与驱动状态。建议在开始任何部署教程之前先完成本篇。</p><ul><li><strong>适合人群</strong>：首次在 AMD GPU 上搭建 ROCm 环境的用户</li><li><strong>难度等级</strong>：⭐⭐</li><li><strong>预计时间</strong>：1 小时</li></ul><p>📖 <a href="/hello-rocm/zh/01-deploy/gemma4/env-prepare-ubuntu24-rocm7">开始学习环境准备教程（Gemma4）</a><br> 📎 参考：<a href="/hello-rocm/zh/01-deploy/qwen3/env-prepare-ubuntu24-rocm7">Qwen3 版本</a> · <a href="/hello-rocm/zh/01-deploy/qwen3.5/env-prepare-ubuntu24-rocm7">Qwen3.5 版本</a></p><hr><h3 id="gemma-4-模型介绍" tabindex="-1">Gemma 4 模型介绍 <a class="header-anchor" href="#gemma-4-模型介绍" aria-label="Permalink to &quot;Gemma 4 模型介绍&quot;">​</a></h3><p>  在开始部署前，推荐先阅读 Gemma 4 模型介绍，了解 Gemma 4 E2B / E4B / 31B / 26B A4B 四个版本的架构特点、能力差异与硬件选择建议，便于按自身环境挑选合适的模型。</p><ul><li><strong>适合人群</strong>：第一次使用 Gemma 4 的用户</li><li><strong>难度等级</strong>：⭐</li><li><strong>预计时间</strong>：15 分钟</li></ul><p>📖 <a href="/hello-rocm/zh/01-deploy/gemma4/gemma4_model">阅读 Gemma 4 模型介绍</a></p><hr><h3 id="lm-studio-零基础大模型部署" tabindex="-1">LM Studio 零基础大模型部署 <a class="header-anchor" href="#lm-studio-零基础大模型部署" aria-label="Permalink to &quot;LM Studio 零基础大模型部署&quot;">​</a></h3><p>  LM Studio 是一款用户友好的桌面应用，支持在本地运行大语言模型。本教程以 <strong>Gemma 4 E4B-it Q4_K_M</strong> 为例，指导你如何在 AMD GPU 上使用 LM Studio + ROCm 版 llama.cpp 后端部署和运行大模型。</p><ul><li><strong>适合人群</strong>：零基础用户、希望快速体验大模型的用户</li><li><strong>难度等级</strong>：⭐</li><li><strong>预计时间</strong>：30 分钟</li></ul><p>📖 <a href="/hello-rocm/zh/01-deploy/gemma4/lm-studio-rocm7-deploy">开始学习 LM Studio 部署教程（Gemma4）</a><br> 📎 参考：<a href="/hello-rocm/zh/01-deploy/qwen3/lm-studio-rocm7-deploy">Qwen3 版本</a> · <a href="/hello-rocm/zh/01-deploy/qwen3.5/lm-studio-rocm7-deploy">Qwen3.5 版本</a></p><hr><h3 id="vllm-零基础大模型部署" tabindex="-1">vLLM 零基础大模型部署 <a class="header-anchor" href="#vllm-零基础大模型部署" aria-label="Permalink to &quot;vLLM 零基础大模型部署&quot;">​</a></h3><p>  vLLM 是一个高性能的大模型推理和服务框架，支持高效的 PagedAttention 和连续批处理。本教程以 <strong>Gemma 4 E4B-it</strong> 为例，分别介绍基于官方 ROCm vLLM Docker 镜像的快速启动方式，以及从源码手动编译 Triton / FlashAttention / vLLM 的进阶方式。</p><ul><li><strong>适合人群</strong>：需要搭建推理服务的开发者</li><li><strong>难度等级</strong>：⭐⭐</li><li><strong>预计时间</strong>：1 小时</li></ul><p>📖 <a href="/hello-rocm/zh/01-deploy/gemma4/vllm-rocm7-deploy">开始学习 vLLM 部署教程（Gemma4）</a><br> 📎 参考：<a href="/hello-rocm/zh/01-deploy/qwen3/vllm-rocm7-deploy">Qwen3 版本</a> · <a href="/hello-rocm/zh/01-deploy/qwen3.5/vllm-rocm7-deploy">Qwen3.5 版本</a></p><hr><h3 id="ollama-零基础大模型部署" tabindex="-1">Ollama 零基础大模型部署 <a class="header-anchor" href="#ollama-零基础大模型部署" aria-label="Permalink to &quot;Ollama 零基础大模型部署&quot;">​</a></h3><p>  Ollama 是一个快速服务大语言模型和视觉语言模型的框架，具有高效的后端运行时。本教程以 <strong>Gemma 4 E4B-it Q4_K_M</strong> 为例，指导你如何在 AMD GPU 上使用 Ollama（ROCm 版 llama.cpp 后端）部署大模型，并给出 tokens/s 测速示例。</p><ul><li><strong>适合人群</strong>：希望一条命令拉起本地推理服务的开发者</li><li><strong>难度等级</strong>：⭐⭐</li><li><strong>预计时间</strong>：1 小时</li></ul><p>📖 <a href="/hello-rocm/zh/01-deploy/gemma4/ollama-rocm7-deploy">开始学习 Ollama 部署教程（Gemma4）</a><br> 📎 参考：<a href="/hello-rocm/zh/01-deploy/qwen3/ollama-rocm7-deploy">Qwen3 版本</a> · <a href="/hello-rocm/zh/01-deploy/qwen3.5/ollama-rocm7-deploy">Qwen3.5 版本</a></p><hr><h3 id="llama-cpp-零基础大模型部署" tabindex="-1">llama.cpp 零基础大模型部署 <a class="header-anchor" href="#llama-cpp-零基础大模型部署" aria-label="Permalink to &quot;llama.cpp 零基础大模型部署&quot;">​</a></h3><p>  llama.cpp 是一个轻量且高性能的推理后端，支持 GGUF 等多种模型格式，并已提供针对 ROCm 的优化版本。本教程以 <strong>Gemma 4 E4B-it Q4_K_M（GGUF）</strong> 为例，介绍如何在 Ubuntu 24.04 + ROCm 7+ 环境下使用预编译二进制与 Docker 两种方式部署主流模型。</p><ul><li><strong>适合人群</strong>：希望用命令行 / REST API 自由编排推理流程的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：1.5 小时</li></ul><p>📖 <a href="/hello-rocm/zh/01-deploy/gemma4/llamacpp-rocm7-deploy">开始学习 llama.cpp 部署教程（Gemma4）</a><br> 📎 参考：<a href="/hello-rocm/zh/01-deploy/qwen3/llamacpp-rocm7-deploy">Qwen3 版本</a> · <a href="/hello-rocm/zh/01-deploy/qwen3.5/llamacpp-rocm7-deploy">Qwen3.5 版本</a></p><hr><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><h3 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h3><ul><li>AMD GPU（支持 ROCm 的显卡，如 RX 7000 / 9000 系列、Ryzen AI MAX / AI 300、Instinct MI 系列等）</li><li>建议显存 8GB 以上（Gemma 4 E4B Q4_K_M 量化版本可在 8GB 显存下运行；如需原生 bfloat16 推理或更大模型，请参考对应教程的显存建议）</li></ul><h3 id="软件要求" tabindex="-1">软件要求 <a class="header-anchor" href="#软件要求" aria-label="Permalink to &quot;软件要求&quot;">​</a></h3><ul><li>操作系统：Linux (Ubuntu 22.04+) 或 Windows 11</li><li>ROCm 7.10.0 或更高版本</li><li>Python 3.10+</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details><summary>Q: 如何确认我的 AMD GPU 是否支持 ROCm？</summary><p>请参考 <a href="https://rocm.docs.amd.com/projects/install-on-linux/en/latest/reference/system-requirements.html" target="_blank" rel="noreferrer">ROCm 官方支持列表</a> 查看支持的 GPU 型号。</p></details><details><summary>Q: 部署时遇到 &quot;HIP error&quot; 怎么办？</summary><ol><li>确认 ROCm 已正确安装</li><li>检查环境变量是否正确设置</li><li>尝试重启系统后再次运行</li></ol></details><details><summary>Q: 下载 Gemma 4 时提示无权限？</summary><p>Gemma 系列模型需要先在 Hugging Face 对应模型页（例如 <a href="https://huggingface.co/google/gemma-4-E4B-it">google/gemma-4-E4B-it</a>）点击 <strong>Agree &amp; Access</strong>，然后使用具备 <code>read</code> 权限的 Hugging Face Token 登录或通过 <code>HF_TOKEN</code> 注入容器 / 进程。</p></details><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm 官方文档</a></li><li><a href="https://docs.vllm.ai/" target="_blank" rel="noreferrer">vLLM 官方文档</a></li><li><a href="https://docs.ollama.com/" target="_blank" rel="noreferrer">Ollama 官方文档</a></li><li><a href="https://github.com/ggerganov/llama.cpp" target="_blank" rel="noreferrer">llama.cpp 仓库</a></li><li><a href="https://huggingface.co/collections/google/gemma-4" target="_blank" rel="noreferrer">Hugging Face Gemma 4 模型合集</a></li></ul><hr><div align="center"><p><strong>欢迎贡献更多部署教程！</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">提交 Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">提交 PR</a></p></div>`,51)])])}const u=e(n,[["render",t]]);export{d as __pageData,u as default};
